```py
import sys
import pathlib
import duckdb
import time
import ctypes
from ctypes import wintypes
import os
import gc


def print_env():
    print(
        "Microsoft Store"
        if any(p.lower() == "windowsapps" for p in pathlib.Path(sys.executable).parts)
        else "Not Microsoft Store"
    )

    print(f"{sys.version=}")
    print(f"{duckdb.__version__=}")


def print_appcontainer_status():
    TOKEN_QUERY = 0x0008
    TokenIsAppContainer = 29
    DWORD = ctypes.wintypes.DWORD
    BOOL = ctypes.wintypes.BOOL
    LPWSTR = ctypes.wintypes.LPWSTR

    advapi32 = ctypes.windll.advapi32
    kernel32 = ctypes.windll.kernel32

    # --- Check AppContainer ---
    hProc = kernel32.GetCurrentProcess()
    hToken = ctypes.wintypes.HANDLE()
    advapi32.OpenProcessToken(hProc, TOKEN_QUERY, ctypes.byref(hToken))

    val = DWORD()
    size = DWORD(ctypes.sizeof(val))
    in_appcontainer = False
    if advapi32.GetTokenInformation(
        hToken, TokenIsAppContainer, ctypes.byref(val), size, ctypes.byref(size)
    ):
        in_appcontainer = bool(val.value)

    # --- Check MSIX Package Identity ---
    package_len = DWORD(0)
    res = kernel32.GetCurrentPackageFullName(ctypes.byref(package_len), None)
    in_msix = res == 122  # ERROR_INSUFFICIENT_BUFFER means yes

    print(f"In AppContainer: {in_appcontainer}")
    print(f"In MSIX Package: {in_msix}")


print_env()
print_appcontainer_status()

times = []
with duckdb.connect() as con:
    con.execute(
        "create table foo as select random(), r, r || 'something', r || 'somethingelse2', r || 'somethingelse3', r || 'somethingelse4', r || 'somethingelse5' from range(10_000_000) t(r)"
    )

    for i in range(100):
        f = "/tmp/myfile.parquet"
        if os.path.exists(f):
            os.unlink(f)

        start = time.perf_counter()

        con.execute("copy foo to '/tmp/myfile.parquet'")
        end = time.perf_counter()
        print(f"Elapsed: {(end - start):.2f}")
        times.append(end - start)

        if i % 10 == 9:
            rolling_avg = sum(times[-10:]) / len(times[-10:])
            print(f"{i}: avg of last 10: {rolling_avg:2f}")

    print(f"Average: {(sum(times) / len(times)):.2f}")

```


